Use MSTest's `[DataTestMethod]` with `[DataRow]` to make it data-driven. Each new case becomes one line instead of a whole method:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Validation.Tests;

[TestClass]
public sealed class InputValidatorTests
{
    [DataTestMethod]
    [DataRow("",              false, "Input cannot be empty")]
    [DataRow("ab",            false, "Input must be at least 3 characters")]
    [DataRow("hello<script>", false, "Input contains invalid characters")]
    [DataRow(null,            false, "Input cannot be empty")]
    [DataRow("   ",           false, "Input cannot be empty")]
    [DataRow("hello-world",   true,  null)]
    [DataRow("abc",           true,  null)]
    public void Validate_ReturnsExpectedResult(
        string? input, bool expectedValid, string? expectedError)
    {
        var validator = new InputValidator();
        var result = validator.Validate(input);
        Assert.AreEqual(expectedValid, result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    // DynamicData handles inputs that can't be compile-time constants
    [DataTestMethod]
    [DynamicData(nameof(BoundaryLengthCases), DynamicDataSourceType.Method)]
    public void Validate_BoundaryLength_ReturnsExpectedResult(
        string input, bool expectedValid, string? expectedError)
    {
        var validator = new InputValidator();
        var result = validator.Validate(input);
        Assert.AreEqual(expectedValid, result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    private static IEnumerable<object?[]> BoundaryLengthCases()
    {
        yield return [new string('a', 255), true,  null];
        yield return [new string('x', 256), false, "Input must not exceed 255 characters"];
    }
}
```

**Key changes:**
- **`[DataRow]`** — each case is one attribute line; adding a case = adding a row
- **`[DynamicData]`** — handles the boundary-length cases that need `new string(c, n)` (not valid in attribute arguments)
- Validator construction stays inline since it's a single line — extract to a field/`[TestInitialize]` if it gains constructor dependencies later
